class InMemoryCatalog:
    def __init__(self, sku_to_product: Dict[str, Dict[str, Any]]):
        self.sku_to_product = sku_to_product

    def get_product(self, sku: str) -> Optional[Dict[str, Any]]:
        return self.sku_to_product.get(sku)


class InMemoryDiscountStore:
    def __init__(self, code_to_rule: Dict[str, DiscountRule]):
        self.code_to_rule = {k.upper(): v for k, v in code_to_rule.items()}

    def get_rule(self, code: str) -> Optional[DiscountRule]:
        return self.code_to_rule.get(code.upper())


class InMemoryOrderStore:
    def __init__(self):
        self.orders: Dict[str, OrderRecord] = {}

    def create(self, order: OrderRecord) -> None:
        if order.order_id in self.orders:
            raise OrderCreationError("Duplicate order_id")
        self.orders[order.order_id] = order

    def get(self, order_id: str) -> Optional[OrderRecord]:
        return self.orders.get(order_id)


# -----------------------------
# Step 1: validate cart items
