def validate_cart_items(
    cart_items: List[CartItem],
    catalog: InMemoryCatalog,
    currency: str = "USD",
) -> Dict[str, Any]:
    if not cart_items:
        raise CartValidationError("Cart is empty")

    validated: List[ValidatedItem] = []
    subtotal = Decimal("0.00")

    for item in cart_items:
        if not item.sku or not isinstance(item.sku, str):
            raise CartValidationError("Invalid SKU")
        if not isinstance(item.quantity, int) or item.quantity <= 0:
            raise CartValidationError(f"Invalid quantity for SKU {item.sku}")

        product = catalog.get_product(item.sku)
        if not product:
            raise CartValidationError(f"Unknown SKU {item.sku}")

        if not product.get("active", True):
            raise CartValidationError(f"Inactive product {item.sku}")

        stock = product.get("stock", None)
        if stock is not None and item.quantity > int(stock):
            raise CartValidationError(f"Insufficient stock for SKU {item.sku}")

        unit_price = safe_decimal(product.get("price"))
        if unit_price < Decimal("0.00"):
            raise CartValidationError(f"Invalid price for SKU {item.sku}")

        unit_price = money(unit_price)
        line_subtotal = money(unit_price * item.quantity)

        validated_item = ValidatedItem(
            sku=item.sku,
            name=str(product.get("name", item.sku)),
            unit_price=unit_price,
            quantity=item.quantity,
            line_subtotal=line_subtotal,
        )
        validated.append(validated_item)
        subtotal += line_subtotal

    subtotal = money(subtotal)

    return {
        "currency": currency,
        "items": tuple(validated),
        "subtotal": subtotal,
    }


# -----------------------------
# Step 2: apply discount codes with permission/tier checks
