def _check_user_can_use_discount(user: User, rule: DiscountRule) -> None:
    if rule.admin_only and not user.is_admin:
        raise DiscountValidationError(f"Discount code {rule.code} is admin-only")

    if rule.allowed_tiers is not None and user.tier not in rule.allowed_tiers:
        raise DiscountValidationError(
            f"Discount code {rule.code} not allowed for tier {user.tier}"
        )

    missing = [p for p in rule.requires_permissions if p not in user.permissions]
    if missing:
        raise DiscountValidationError(
            f"Discount code {rule.code} requires permissions: {', '.join(missing)}"
        )


def apply_discount_codes(
    user: User,
    validated_cart: Dict[str, Any],
    discount_codes: List[str],
    discount_store: InMemoryDiscountStore,
) -> Dict[str, Any]:
    currency = validated_cart["currency"]
    items: Tuple[ValidatedItem, ...] = validated_cart["items"]
    subtotal: Decimal = validated_cart["subtotal"]

    codes_norm = []
    for c in discount_codes or []:
        if c is None:
            continue
        c = str(c).strip()
        if c:
            codes_norm.append(c.upper())

    if not codes_norm:
        return {
            **validated_cart,
            "discount_codes": tuple(),
            "discount_total": Decimal("0.00"),
            "discount_breakdown": tuple(),
            "taxable_amount": subtotal,
        }

    seen = set()
    unique_codes = []
    for c in codes_norm:
        if c not in seen:
            unique_codes.append(c)
            seen.add(c)

    rules: List[DiscountRule] = []
    for code in unique_codes:
        rule = discount_store.get_rule(code)
        if not rule:
            raise DiscountValidationError(f"Unknown discount code {code}")
        _check_user_can_use_discount(user, rule)
        if subtotal < rule.min_subtotal:
            raise DiscountValidationError(
                f"Discount code {code} requires min subtotal {money(rule.min_subtotal)}"
            )
        rules.append(rule)

    non_stack = [r for r in rules if not r.stackable]
    if len(non_stack) > 1:
        raise DiscountValidationError("Multiple non-stackable discount codes provided")

    discount_total = Decimal("0.00")
    breakdown = []

    base = subtotal
    for rule in rules:
        if rule.kind == "percent":
            pct = safe_decimal(rule.value)
            if pct <= 0 or pct > 100:
                raise DiscountValidationError(f"Invalid percent value for {rule.code}")
            amount = money(base * (pct / Decimal("100")))
        elif rule.kind == "amount":
            amt = safe_decimal(rule.value)
            if amt <= 0:
                raise DiscountValidationError(f"Invalid amount value for {rule.code}")
            amount = money(amt)
        else:
            raise DiscountValidationError(f"Invalid discount kind for {rule.code}")

        remaining = clamp_money_nonnegative(subtotal - discount_total)
        amount = min(amount, remaining)

        discount_total = money(discount_total + amount)
        breakdown.append({"code": rule.code, "amount": amount, "kind": rule.kind})

        if rule.stackable:
            base = clamp_money_nonnegative(base - amount)

    taxable_amount = clamp_money_nonnegative(subtotal - discount_total)

    return {
        "currency": currency,
        "items": items,
        "subtotal": subtotal,
        "discount_codes": tuple(r.code for r in rules),
        "discount_total": discount_total,
        "discount_breakdown": tuple(breakdown),
        "taxable_amount": taxable_amount,
    }


# -----------------------------
# Step 3: calculate tax
# -----------------------------

def calculate_tax(
    discounted_cart: Dict[str, Any],
    tax_rate: Decimal,
    tax_inclusive: bool = False,
) -> Dict[str, Any]:
    if tax_rate is None:
        raise TaxCalculationError("tax_rate is required")

    tax_rate = safe_decimal(tax_rate)
    if tax_rate < 0 or tax_rate > 1:
        raise TaxCalculationError("tax_rate must be a fraction between 0 and 1")

    taxable_amount: Decimal = discounted_cart["taxable_amount"]

    if tax_inclusive:
        if tax_rate == 0:
            tax_total = Decimal("0.00")
            total = taxable_amount
        else:
            tax_total = money(taxable_amount - (taxable_amount / (Decimal("1.0") + tax_rate)))
            total = taxable_amount
    else:
        tax_total = money(taxable_amount * tax_rate)
        total = money(taxable_amount + tax_total)

    return {
        **discounted_cart,
        "tax_rate": tax_rate,
        "tax_total": tax_total,
        "total": total,
    }


