# Step 4: process payment
# -----------------------------

class PaymentGateway:
    def charge(self, *, user: User, amount: Decimal, currency: str, payment_method: Dict[str, Any]) -> PaymentResult:
        raise NotImplementedError


class DummyPaymentGateway(PaymentGateway):
    def charge(self, *, user: User, amount: Decimal, currency: str, payment_method: Dict[str, Any]) -> PaymentResult:
        amount = money(amount)
        if amount <= 0:
            raise PaymentProcessingError("Charge amount must be > 0")

        if not isinstance(payment_method, dict) or not payment_method.get("type"):
            raise PaymentProcessingError("Invalid payment_method")

        if payment_method.get("fail") is True:
            raise PaymentProcessingError("Payment failed by request")

        txn = f"txn_{uuid4().hex}"
        return PaymentResult(
            provider="dummy",
            transaction_id=txn,
            status="captured",
            amount=amount,
            currency=currency,
            raw={"payment_method_type": payment_method.get("type")},
        )


def process_payment(
    user: User,
    taxed_cart: Dict[str, Any],
    payment_method: Dict[str, Any],
    gateway: PaymentGateway,
) -> Dict[str, Any]:
    amount: Decimal = taxed_cart["total"]
    currency: str = taxed_cart["currency"]

    payment = gateway.charge(user=user, amount=amount, currency=currency, payment_method=payment_method)
    if payment.status not in ("authorized", "captured"):
        raise PaymentProcessingError("Payment not successful")

    if money(payment.amount) != money(amount) or payment.currency != currency:
        raise PaymentProcessingError("Payment amount/currency mismatch")

    return {
        **taxed_cart,
        "payment": payment,
    }


