def create_order_record(
    user: User,
    paid_cart: Dict[str, Any],
    order_store: InMemoryOrderStore,
    metadata: Optional[Dict[str, Any]] = None,
) -> OrderRecord:
    try:
        order = OrderRecord(
            order_id=f"ord_{uuid4().hex}",
            user_id=user.user_id,
            currency=paid_cart["currency"],
            items=paid_cart["items"],
            discount_codes=paid_cart.get("discount_codes", tuple()),
            subtotal=money(paid_cart["subtotal"]),
            discount_total=money(paid_cart.get("discount_total", Decimal("0.00"))),
            taxable_amount=money(paid_cart.get("taxable_amount", paid_cart["subtotal"])),
            tax_total=money(paid_cart.get("tax_total", Decimal("0.00"))),
            total=money(paid_cart["total"]),
            payment=paid_cart["payment"],
            created_at=time.time(),
            metadata=dict(metadata or {}),
        )
        order_store.create(order)
        return order
    except KeyError as e:
        raise OrderCreationError(f"Missing required field: {e}") from e


# -----------------------------
# Orchestration: multi-step checkout
# -----------------------------

def checkout(
    *,
    user: User,
    cart_items: List[CartItem],
    discount_codes: Optional[List[str]],
    payment_method: Dict[str, Any],
    catalog: InMemoryCatalog,
    discount_store: InMemoryDiscountStore,
    order_store: InMemoryOrderStore,
    gateway: PaymentGateway,
    tax_rate: Decimal,
    currency: str = "USD",
    tax_inclusive: bool = False,
    order_metadata: Optional[Dict[str, Any]] = None,
) -> OrderRecord:
    s1 = validate_cart_items(cart_items=cart_items, catalog=catalog, currency=currency)
    s2 = apply_discount_codes(user=user, validated_cart=s1, discount_codes=discount_codes or [], discount_store=discount_store)
    s3 = calculate_tax(discounted_cart=s2, tax_rate=tax_rate, tax_inclusive=tax_inclusive)
    s4 = process_payment(user=user, taxed_cart=s3, payment_method=payment_method, gateway=gateway)
    order = create_order_record(user=user, paid_cart=s4, order_store=order_store, metadata=order_metadata)
    return order